// generar_241_analisis_afinado.js
// CHIQUI Entre Señales — Afinado de Análisis (síntesis, paseo, rutinas)
//
// Tres ajustes tras probar la refactorización del 237:
//
// 1) RESUMEN INTELIGENTE ahora es síntesis + conclusión de una línea:
//    - Sin recomendaciones repetidas (antes decía "coméntalo con tu
//      veterinario" en el resumen, en los insights de abajo y en las
//      tarjetas — eso queda solo en las tarjetas).
//    - Una síntesis compacta: días registrados, % de normalidad,
//      episodios notables y seguimientos, todo en 1-3 frases.
//    - Cierra SIEMPRE con "Estado general: [Estable / Requiere
//      observación / Seguimiento recomendado / Consulta veterinaria
//      prioritaria]" con su color de semáforo. No reemplaza el juicio
//      veterinario — ayuda al tutor a entender rápido el panorama.
//
// 2) PASEO:
//    - Antes: "Paseo este mes (estimado)" con ⏱️
//    - Ahora: "🕒 Paseo este mes" sin palabra estimado en el título.
//    - Cuando ningún registro del período tiene tiempo exacto, aparece
//      debajo un "≈ Basado en registros aproximados" — más elegante.
//    - Cuando al menos un registro es exacto, el título queda limpio.
//    - El gráfico "Últimos 7 días" también pierde la palabra estimado.
//
// 3) RUTINAS DE CUIDADO con semáforo automático de prioridad:
//    - 🔴 rojo: retrasada 3+ días → "Hace 3 días estaba pendiente"
//    - 🟠 naranjo: retrasada 1-2 días o corresponde hoy → "Corresponde
//      realizarla hoy" / "Estaba pendiente hace 2 días"
//    - 🟡 amarillo: próxima en 1-3 días → "Te tocaría mañana"
//    - 🟢 verde: próxima en 4+ días → "Te tocaría de nuevo en N días"
//    Así la tarjeta comunica su prioridad de un vistazo por color.
//
// Solo reescribe app/analisis/page.tsx. No hay SQL.
//
// Uso:
//   node generar_241_analisis_afinado.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/analisis/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
